/* ===== RESET & BASE ===== */
*, *::before, *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  --bg: #0a0a0a;
  --bg-card: #111111;
  --bg-hover: #1a1a1a;
  --text: #f5f5f5;
  --text-secondary: #888888;
  --text-muted: #555555;
  --accent: #c8ff00;
  --accent-dim: rgba(200, 255, 0, 0.15);
  --border: rgba(255, 255, 255, 0.08);
  --border-hover: rgba(255, 255, 255, 0.15);
  --radius: 16px;
  --radius-sm: 10px;
  --radius-pill: 100px;
  --font: 'DM Sans', -apple-system, sans-serif;
  --font-display: 'Space Grotesk', sans-serif;
  --transition: 0.3s cubic-bezier(0.16, 1, 0.3, 1);
  --max-width: 1200px;
  --px: 24px;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden;
}

a {
  color: inherit;
  text-decoration: none;
}

em {
  font-style: italic;
  color: var(--accent);
}

/* ===== GRAIN OVERLAY ===== */
.grain {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 9999;
  opacity: 0.03;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
  background-repeat: repeat;
}

/* ===== CURSOR GLOW ===== */
.cursor-glow {
  position: fixed;
  width: 500px;
  height: 500px;
  border-radius: 50%;
  background: radial-gradient(circle, var(--accent-dim) 0%, transparent 70%);
  pointer-events: none;
  z-index: 0;
  transform: translate(-50%, -50%);
  transition: left 0.15s ease-out, top 0.15s ease-out;
  opacity: 0;
}

body:hover .cursor-glow {
  opacity: 1;
}

/* ===== NAVIGATION ===== */
.nav {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 100;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px var(--px);
  max-width: var(--max-width);
  margin: 0 auto;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

.nav-logo {
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 700;
  width: 44px;
  height: 44px;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1px solid var(--border);
  border-radius: 50%;
  transition: border-color var(--transition), background var(--transition);
}

.nav-logo:hover {
  border-color: var(--accent);
  background: var(--accent-dim);
}

.nav-links {
  display: flex;
  gap: 32px;
  font-size: 14px;
  font-weight: 500;
  color: var(--text-secondary);
}

.nav-links a {
  transition: color var(--transition);
  position: relative;
}

.nav-links a::after {
  content: '';
  position: absolute;
  bottom: -4px;
  left: 0;
  width: 0;
  height: 1px;
  background: var(--accent);
  transition: width var(--transition);
}

.nav-links a:hover {
  color: var(--text);
}

.nav-links a:hover::after {
  width: 100%;
}

/* ===== HERO ===== */
.hero {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  text-align: center;
  padding: 120px var(--px) 80px;
  position: relative;
}

.hero-badge {
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: var(--accent);
  background: var(--accent-dim);
  padding: 8px 20px;
  border-radius: var(--radius-pill);
  border: 1px solid rgba(200, 255, 0, 0.2);
  margin-bottom: 40px;
  animation: fadeUp 0.8s ease-out both;
}

.hero-title {
  font-family: var(--font-display);
  font-size: clamp(60px, 12vw, 140px);
  font-weight: 700;
  line-height: 0.95;
  letter-spacing: -3px;
  margin-bottom: 32px;
  animation: fadeUp 0.8s ease-out 0.15s both;
}

.hero-title .line {
  display: block;
}

.hero-title .outline {
  -webkit-text-stroke: 2px var(--text);
  color: transparent;
  transition: color 0.4s ease, -webkit-text-stroke 0.4s ease;
}

.hero-title:hover .outline {
  color: var(--accent);
  -webkit-text-stroke: 0px;
}

.hero-sub {
  font-size: clamp(16px, 2vw, 20px);
  color: var(--text-secondary);
  line-height: 1.6;
  max-width: 500px;
  animation: fadeUp 0.8s ease-out 0.3s both;
}

.hero-scroll {
  position: absolute;
  bottom: 40px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  font-size: 12px;
  color: var(--text-muted);
  letter-spacing: 2px;
  text-transform: uppercase;
  animation: fadeUp 0.8s ease-out 0.5s both;
}

.scroll-line {
  width: 1px;
  height: 50px;
  background: linear-gradient(to bottom, var(--accent), transparent);
  animation: scrollPulse 2s ease-in-out infinite;
}

@keyframes scrollPulse {
  0%, 100% { opacity: 1; transform: scaleY(1); }
  50% { opacity: 0.4; transform: scaleY(0.6); }
}

@keyframes fadeUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* ===== MARQUEE ===== */
.marquee {
  padding: 24px 0;
  border-top: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
  overflow: hidden;
  user-select: none;
}

.marquee-track {
  display: flex;
  align-items: center;
  gap: 32px;
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 500;
  color: var(--text-muted);
  white-space: nowrap;
  animation: marqueeScroll 20s linear infinite;
  width: max-content;
}

.marquee-track .dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--accent);
  flex-shrink: 0;
}

@keyframes marqueeScroll {
  0% { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}

/* ===== WORK SECTION ===== */
.section-label {
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: var(--text-muted);
  margin-bottom: 48px;
}

.work {
  padding: 120px var(--px);
  max-width: var(--max-width);
  margin: 0 auto;
}

.projects {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 24px;
}

.project-card {
  background: var(--bg-card);
  border-radius: var(--radius);
  border: 1px solid var(--border);
  overflow: hidden;
  transition: border-color var(--transition), transform var(--transition);
  display: flex;
  flex-direction: column;
}

.project-card:hover {
  border-color: var(--border-hover);
  transform: translateY(-4px);
}

.project-img {
  height: 260px;
  position: relative;
  overflow: hidden;
  transition: transform 0.6s cubic-bezier(0.16, 1, 0.3, 1);
}

.project-card:hover .project-img {
  transform: scale(1.03);
}

.project-img-inner {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: flex-start;
  justify-content: flex-start;
  padding: 20px;
}

.project-tag {
  font-size: 12px;
  font-weight: 600;
  padding: 6px 14px;
  border-radius: var(--radius-pill);
  background: rgba(0, 0, 0, 0.4);
  backdrop-filter: blur(8px);
  color: white;
  letter-spacing: 0.5px;
}

.project-info {
  padding: 28px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  flex: 1;
}

.project-info h3 {
  font-family: var(--font-display);
  font-size: 24px;
  font-weight: 600;
}

.project-info p {
  font-size: 15px;
  color: var(--text-secondary);
  line-height: 1.6;
  flex: 1;
}

.project-cta {
  font-size: 14px;
  font-weight: 600;
  color: var(--accent);
  transition: letter-spacing var(--transition);
}

.project-card:hover .project-cta {
  letter-spacing: 1px;
}

/* ===== ABOUT ===== */
.about {
  padding: 120px var(--px);
  max-width: var(--max-width);
  margin: 0 auto;
}

.about-grid {
  display: grid;
  grid-template-columns: 1fr 1.3fr;
  gap: 80px;
  align-items: start;
}

.about-heading {
  font-family: var(--font-display);
  font-size: clamp(36px, 5vw, 56px);
  font-weight: 700;
  line-height: 1.1;
  letter-spacing: -1px;
  margin-top: 16px;
}

.about-text {
  font-size: 16px;
  color: var(--text-secondary);
  line-height: 1.7;
  margin-bottom: 16px;
}

.about-details {
  margin-top: 40px;
  display: flex;
  flex-direction: column;
  gap: 28px;
}

.detail-group h4 {
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: var(--text-muted);
  margin-bottom: 12px;
}

.pills {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.pill {
  font-size: 13px;
  font-weight: 500;
  padding: 8px 18px;
  border-radius: var(--radius-pill);
  background: var(--bg-card);
  border: 1px solid var(--border);
  color: var(--text-secondary);
  transition: border-color var(--transition), color var(--transition), background var(--transition);
}

.pill:hover {
  border-color: var(--accent);
  color: var(--accent);
  background: var(--accent-dim);
}

.stats-row {
  display: flex;
  gap: 48px;
  margin-top: 48px;
  padding-top: 48px;
  border-top: 1px solid var(--border);
}

.stat-num {
  font-family: var(--font-display);
  font-size: 40px;
  font-weight: 700;
  color: var(--accent);
  display: block;
  line-height: 1;
}

.stat-label {
  font-size: 14px;
  color: var(--text-muted);
  margin-top: 6px;
  display: block;
}

/* ===== CONTACT ===== */
.contact {
  padding: 120px var(--px);
  max-width: var(--max-width);
  margin: 0 auto;
  text-align: center;
}

.contact-heading {
  font-family: var(--font-display);
  font-size: clamp(40px, 6vw, 72px);
  font-weight: 700;
  line-height: 1.1;
  letter-spacing: -2px;
  margin-bottom: 60px;
}

.contact-links {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 16px;
  max-width: 700px;
  margin: 0 auto;
}

.contact-link {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  padding: 32px 24px;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  transition: border-color var(--transition), transform var(--transition), background var(--transition);
}

.contact-link:hover {
  border-color: var(--accent);
  background: var(--accent-dim);
  transform: translateY(-3px);
}

.contact-link-label {
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: var(--text-muted);
}

.contact-link-value {
  font-size: 15px;
  font-weight: 500;
  color: var(--text);
}

.contact-link:hover .contact-link-value {
  color: var(--accent);
}

/* ===== FOOTER ===== */
.footer {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 32px var(--px);
  border-top: 1px solid var(--border);
  max-width: var(--max-width);
  margin: 0 auto;
  font-size: 13px;
  color: var(--text-muted);
}

/* ===== SCROLL REVEAL ===== */
.reveal {
  opacity: 0;
  transform: translateY(40px);
  transition: opacity 0.6s ease-out, transform 0.6s ease-out;
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

/* ===== RESPONSIVE ===== */
@media (max-width: 900px) {
  .projects {
    grid-template-columns: 1fr;
  }

  .about-grid {
    grid-template-columns: 1fr;
    gap: 40px;
  }
}

@media (max-width: 600px) {
  :root {
    --px: 16px;
  }

  .hero-title {
    letter-spacing: -1px;
  }

  .hero-sub br {
    display: none;
  }

  .nav-links {
    gap: 20px;
  }

  .contact-links {
    grid-template-columns: 1fr;
  }

  .stats-row {
    gap: 32px;
  }

  .stat-num {
    font-size: 32px;
  }

  .footer {
    flex-direction: column;
    gap: 8px;
    text-align: center;
  }

  .cursor-glow {
    display: none;
  }

  .marquee-track {
    font-size: 14px;
    gap: 20px;
  }
}

// ===== Cursor Glow =====
const glow = document.getElementById('cursorGlow');

document.addEventListener('mousemove', (e) => {
  glow.style.left = e.clientX + 'px';
  glow.style.top = e.clientY + 'px';
});

// ===== Scroll Reveal =====
const revealTargets = document.querySelectorAll(
  '.project-card, .about-left, .about-right, .contact-link, .stats-row'
);

revealTargets.forEach(el => el.classList.add('reveal'));

const observer = new IntersectionObserver(
  (entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('visible');
      }
    });
  },
  { threshold: 0.15, rootMargin: '0px 0px -40px 0px' }
);

revealTargets.forEach(el => observer.observe(el));

// ===== Staggered reveal for project cards =====
const cards = document.querySelectorAll('.project-card');
cards.forEach((card, i) => {
  card.style.transitionDelay = `${i * 0.1}s`;
});

// ===== Smooth nav background on scroll =====
const nav = document.querySelector('.nav');

window.addEventListener('scroll', () => {
  if (window.scrollY > 60) {
    nav.style.background = 'rgba(10, 10, 10, 0.85)';
    nav.style.borderBottom = '1px solid rgba(255,255,255,0.05)';
  } else {
    nav.style.background = 'transparent';
    nav.style.borderBottom = 'none';
  }
});

// ===== Active nav link highlight =====
const sections = document.querySelectorAll('section[id]');
const navLinks = document.querySelectorAll('.nav-links a');

window.addEventListener('scroll', () => {
  let current = '';
  sections.forEach(section => {
    const top = section.offsetTop - 200;
    if (window.scrollY >= top) {
      current = section.getAttribute('id');
    }
  });

  navLinks.forEach(link => {
    link.style.color = '';
    if (link.getAttribute('href') === `#${current}`) {
      link.style.color = 'var(--text)';
    }
  });
});
